{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/TrailingCommaOnDeclarationSiteRuleEmptyEnumTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

class TrailingCommaOnDeclarationSiteRuleEmptyEnumTest {
    private val trailingCommaOnDeclarationSiteRuleAssertThat =
        KtLintAssertThat.assertThatRule(
            provider = { TrailingCommaOnDeclarationSiteRule() },
            additionalRuleProviders = setOf(
                // WrappingRule must be loaded in order to run TrailingCommaOnCallSiteRule
                RuleProvider { WrappingRule() },
                // Apply the IndentationRule always as additional rule, so that the formattedCode in the unit test looks
                // correct.
                RuleProvider { IndentationRule() },
            ),
        )

    @Test
    fun `Given an empty enum class then do not fail with an internal error`() {
        val code =
            """
            enum class EmptyEnum {
            }
            """.trimIndent()

        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .hasNoLintViolations()
            .isFormattedAs(code)
    }

    @Test
    fun `Given an empty enum class with declarations then do not fail with an internal error`() {
        val code =
            """
            enum class EmptyEnum {
                ;

                fun foo() {}
            }
            """.trimIndent()

        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .hasNoLintViolations()
            .isFormattedAs(code)
    }
}
"}

